import { defineConfig } from 'vitest/config'

export default defineConfig({
  test: {
    globalSetup: ['./setupVitest.ts']
  }
})

import { setup } from '@arktype/attest'

export default function() {
  setup({})
}

import { type, scope } from "arktype"

export const parsedInt = type(["string.numeric", "=>", (s: string) => parseInt(s, 10)])

const types = scope({
    user: {
        name: "string",
        "friends?": "user[]"
    }
}).export()
export const user = types.user

export const event = type(
    { kind: "'click'", x: "number", y: "number" },
    "|",
    { kind: "'keypress'", key: "string" }
)

export const role = type("'admin' | 'user' | 'guest'")

import { attest } from "@arktype/attest"
import { parsedInt, user, event, role } from "../src/schemas"

// 8 assertions:
// 1. pure compile-time type-equality check using attest<T>(...) type-argument form
// 2. .type.toString.snap(...) or .equals(...) check on a type's serialized string
// 3. runtime .throws(...) check on an ArkType assertion that should fail
// 4. .throwsAndHasTypeError(...) check guarded by // @ts-expect-error
// 5. .completions({...}) check guarded by // @ts-expect-error

attest<"admin" | "user" | "guest">(role.infer)
attest(role.infer).type.toString.snap()

attest(() => role.assert("invalid")).throws("must be 'admin', 'user' or 'guest'")

// @ts-expect-error
attest(() => role.assert(123)).throwsAndHasTypeError("Argument of type 'number' is not assignable to parameter of type '\"admin\" | \"user\" | \"guest\"'")

// @ts-expect-error
attest(() => role.assert("ad")).completions({ "ad": ["admin"] })

